"""# **Χρωματισμός Τετραγώνου**

  Θέλουμε να χρωματίσουμε ένα τετράγωνο πλευράς 1. Για να γίνει αυτό, θα χρησιμοποιήσουμε μια συνάρτηση που αντιστοιχίζει σε κάθε σημείο $(x,y)$ με $0 \le x,y \le 1$, τρεις τιμές χρωματικής φωτεινότητας $(r, g, b)$ με $0 \le r, g, b \le 1$ που αντιστοιχούν στην κόκκινη, στην πράσινη και στην μπλέ συνιστώσα.

<p align="center">
  <img src="data:image/svg+xml;base64," alt="Εικόνα" width="550" height="300">
</p>


  Για παράδειγμα, η συνάρτηση $f(x,y) = (x,y,0)$ βάφει:
- το σημείο $(x,y) = (0,0)$ μαύρο, δλδ $(r,g,b) = (0,0,0)$,
- το σημείο $(x,y) = (1,0)$ κόκκινο, δλδ $(r,g,b) = (1,0,0)$,
- το σημείο $(x,y) = (0,1)$ πράσινο, δλδ $(r,g,b) = (0,1,0)$,
- το σημείο $(x,y) = (1,1)$ κίτρινο, δλδ $(r,g,b) = (1,1,0)$ συνδυάζοντας την κόκκινη και πράσινη συνιστώσα
- κάθε άλλο σημείο ένα μείγμα αυτών των χρωμάτων.



Η μέθοδος `function2image` μετατρέπει μια δοσμένη συνάρτηση σε εικόνα.

"""

import torch
import numpy as np
import matplotlib.pyplot as plt
import types
import math

def function2image(f, grid_size=500):
    x_vals = torch.linspace(0, 1, grid_size)
    y_vals = torch.linspace(0, 1, grid_size)
    X, Y = torch.meshgrid(x_vals, y_vals, indexing='xy')

    X_flat = X.flatten()
    Y_flat = Y.flatten()

    if isinstance(f, types.FunctionType):
        output = torch.tensor([f(x.item(), y.item()) for x, y in zip(X_flat, Y_flat)])
    elif isinstance(f, torch.nn.Module):
        inp = torch.column_stack( (X_flat, Y_flat) )
        output = f( inp ).detach()
    else:
        print("Unsupported function")
        return

    output_image = output.clamp(0, 1).view(grid_size, grid_size, 3)

    plt.imshow(output_image.numpy(), origin="lower")
    plt.axis('off')
    plt.show()

def basic_f(x, y):
    return (x, y, 0)

def easy_f(x, y):
    return (0, 0, abs(x+y - 1))

def medium_f(x, y):
    return ((math.sin(x*15)) * 0.5 +0.5,(math.cos(y*15)) * 0.5+0.5,0)

function2image(basic_f)

"""## Πιο δύσκολες συναρτήσεις με βάση φωτογραφίες"""

from PIL import Image
from torchvision import transforms as T

advanced_img = T.ToTensor()(Image.open("rubiks.jpg").convert("RGB"))
def advanced_f(x, y):
    h, w = advanced_img.shape[1], advanced_img.shape[2]
    xi = min(math.floor(x * w), w - 1)
    yi = min(math.floor((1-y) * h), h - 1)
    return advanced_img[:, yi, xi].tolist()

hard_img = T.ToTensor()(Image.open("cat.jpg").convert("RGB"))
def hard_f(x, y):
    h, w = hard_img.shape[1], hard_img.shape[2]
    xi = min(math.floor(x * w), w - 1)
    yi = min(math.floor((1-y) * h), h - 1)
    return hard_img[:, yi, xi].tolist()


function2image(hard_f)

"""## Η άσκηση

Για την άσκηση θα χρησιμοποιήσουμε μια δοσμένη αρχιτεκτονική νεωρωνικού δικτύου ως συνάρτηση για να χρωματίσουμε το τετράγωνο. Το νευρωνικό δέχεται 2 εισόδους τις συντεταγμένες $(x,y)$ και βγάζει ως έξοδο 3 τιμές που αντιστοιχούν στις φωτεινότητες rgb. Στόχος σας είναι να εκπαιδεύσετε μια τέτοια αρχιτεκτονική για κάθε εικόνα έτσι ώστε να οδηγήσει σε όσο πιο πιστή αναπαράσταση της εικόνας μπορείτε.


<p align="center">
  <img src="data:image/svg+xml;base64," alt="Εικόνα" width="550" height="500">
</p>


 Παρακάτω δίνεται η αρχιτεκτονική και η οπτικοποίηση του νευρωνικού με τυχαία αρχικοποιημένα βάρη.
"""

# Μην πειράξετε την αρχιτεκτονική
import torch
import torch.nn as nn
import torch.optim as optim
import numpy as np
from PIL import Image
import matplotlib.pyplot as plt

def Net():
    return nn.Sequential(
        nn.Linear(2, 20),
        nn.ReLU(),
        nn.Linear(20, 20),
        nn.ReLU(),
        nn.Linear(20, 20),
        nn.ReLU(),
        nn.Linear(20, 20),
        nn.ReLU(),
        nn.Linear(20, 20),
        nn.ReLU(),
        nn.Linear(20, 20),
        nn.ReLU(),
        nn.Linear(20, 3)
    )

net = Net()
function2image(net)

import copy

def train(model, epochs, optimizer, train_loader, test_loader, criterion, scheduler, device):
    best_loss = float('inf')
    best_model_wts = copy.deepcopy(model.state_dict())

    for epoch in range(epochs):
        model.train()
        running_loss = 0.0
        for batch_X, batch_y in train_loader:
            batch_X, batch_y = batch_X.to(device, non_blocking=True), batch_y.to(device, non_blocking=True)
            optimizer.zero_grad()
            outputs = model(batch_X)
            loss = criterion(outputs, batch_y)
            loss.backward()
            optimizer.step()
            running_loss += loss.item()

        train_loss = running_loss / len(train_loader)

        model.eval()
        val_loss = 0.0
        with torch.no_grad():
            for batch_X, batch_y in test_loader:
                batch_X, batch_y = batch_X.to(device), batch_y.to(device)
                outputs = model(batch_X)
                loss = criterion(outputs, batch_y)
                val_loss += loss.item()

        val_loss = val_loss / len(test_loader)
        scheduler.step()

        if val_loss < best_loss:
            best_loss = val_loss
            best_model_wts = copy.deepcopy(model.state_dict())

        if (epoch + 1) % 5 == 0 or epoch == 0:
            print(f"Epoch: {epoch+1}/{epochs} | Train Loss: {train_loss:.6f} | Val Loss: {val_loss:.6f}")

    model.load_state_dict(best_model_wts)
    print(f"Training complete. Best Val Loss: {best_loss:.6f}")

def generate_ds(f, samples=50):
    # Create a more dense grid for better learning
    steps = np.linspace(0, 1, samples)
    X = []
    y = []
    for i in steps:
        for j in steps:
            X.append([i, j])
            y.append(f(i, j))

    X = torch.tensor(X).float()
    y = torch.tensor(y).float()
    return torch.utils.data.TensorDataset(X, y)

tasks = {
    "basic":    basic_f,
    "easy":     easy_f,
    "medium":   medium_f,
    "advanced": advanced_f,
    "hard":     hard_f
}

import torch.nn as nn
from torch.utils.data import DataLoader, random_split

device = "cuda" if torch.cuda.is_available() else "cpu"

def solve_task(task_name):
    print(f"\n--- Training for Task: {task_name} ---")
    net = Net().to(device)
    criterion = nn.MSELoss()
    optimizer = optim.Adam(net.parameters(), lr=0.01)
    scheduler = optim.lr_scheduler.StepLR(optimizer, step_size=10, gamma=0.5)

    # Use much larger batches for harder tasks to speed up GPU processing
    is_hard = task_name in ["advanced", "hard"]
    density = 300 if is_hard else 50
    batch_size = 512 if is_hard else 64
    num_epochs = 500 if is_hard else 50

    full_ds = generate_ds(tasks[task_name], samples=density)
    train_size = int(0.8 * len(full_ds))
    test_size = len(full_ds) - train_size
    train_ds, test_ds = random_split(full_ds, [train_size, test_size])

    train_loader = DataLoader(train_ds, batch_size=batch_size, shuffle=True, num_workers=2, pin_memory=True)
    test_loader = DataLoader(test_ds, batch_size=batch_size, shuffle=False, num_workers=2, pin_memory=True)

    train(net, num_epochs, optimizer, train_loader, test_loader, criterion, scheduler, device)
    return net



# Execute training for all tasks
nets = {}
for task_key in tasks.keys():
    print("target image")
    function2image(tasks[task_key])
    # Using fewer epochs for demonstration, increase for better results
    nets[task_key] = solve_task(task_key).to(device)
    # Preview result
    print(f"Preview for {task_key}:")
    function2image(nets[task_key].to("cpu"))

"""## Υποβολή

Παίρνουμε τα βάρη του νευρωνικού για υποβολή στο site.
"""

import json
def export_weights(net):
    layers = []
    i = 0
    while 2 * i < len(net):
        layer = net[2 * i]
        if isinstance(layer, torch.nn.Linear):
            weight_data = layer.weight.data.cpu().numpy()  # Shape: (num_outputs, num_inputs)
            bias_data = layer.bias.data.cpu().numpy()  # Shape: (num_outputs,)

            weights = weight_data.tolist()
            bias = bias_data.tolist()

            layers.append({
                "weights": weights,
                "bias": bias
            })
        i += 1

    return {"layers": layers}

def export_all_levels(nets, filename="answer.json"):
    result = {}

    for level in ["basic", "easy", "medium", "advanced", "hard"]:
        if level in nets:
            result[level] = export_weights(nets[level])

    with open(filename, 'w') as f:
        json.dump(result, f)

export_all_levels(nets)

# Export all trained networks to the final JSON file
export_all_levels(nets)
print("Successfully exported weights to answer.json")

summary_content = """# Neural Network Colorization - Technical Summary

This document outlines the modifications made to the training pipeline to ensure accurate color reconstruction for the provided tasks.

## 1. Loss Function Correction
- **Issue:** The original code used `CrossEntropyLoss`.
- **Fix:** Changed to `nn.MSELoss()`.
- **Why:** `CrossEntropyLoss` is designed for categorical classification. Since we are predicting continuous RGB values (regression), Mean Squared Error is the appropriate metric to minimize the distance between predicted and actual colors.

## 2. Increased Data Density
- **Issue:** The initial sampling grid (0.1 steps) only provided 100 data points.
- **Fix:** Increased the density to 50 for basic tasks and 200 for 'advanced/hard' tasks.
- **Why:** Complex images (like the rubiks and cat) require a much higher resolution of coordinate-to-color mapping for the neural network to capture fine details and sharp edges.

## 3. Training Loop Improvements
- **Evaluation Metric:** Removed the binary accuracy check (`pred == target`), which is invalid for floating-point tensors, and focused on minimizing the MSE validation loss.
- **Weight Persistence:** Implemented a best-model checkpointing system that saves the weights with the lowest validation loss rather than just the final epoch.
- **Learning Rate Scheduling:** Integrated a `StepLR` scheduler to decay the learning rate, allowing the model to converge more precisely in later epochs.

## 4. Hardware Optimization
- Added logic to automatically detect and use `cuda` (GPU) if available, significantly speeding up training for the high-density datasets.
"""

